{
    // Concrete subclass to test abstract Person
    internal class ConcretePerson : Person { }

    [TestClass]
    public sealed class PersonTests
    {
        [TestMethod]
        public void FullName_WithBothNames_ReturnsLastNameCommaFirstMidName()
        {
            // Arrange
            var person = new ConcretePerson { LastName = "Smith", FirstMidName = "John" };

            // Act
            var result = person.FullName;

            // Assert
            Assert.AreEqual("Smith, John", result);
        }

        [TestMethod]
        public void FullName_WithEmptyStrings_ReturnsCommaSpace()
        {
            var person = new ConcretePerson { LastName = "", FirstMidName = "" };
            Assert.AreEqual(", ", person.FullName);
        }

        [TestMethod]
        public void FullName_WithSpecialCharacters_ReturnsConcatenated()
        {
            var person = new ConcretePerson { LastName = "O'Brien", FirstMidName = "Mary-Jane" };
            Assert.AreEqual("O'Brien, Mary-Jane", person.FullName);
        }

        [TestMethod]
        public void ID_SetAndGet_ReturnsCorrectValue()
        {
            var person = new ConcretePerson { ID = 42 };
            Assert.AreEqual(42, person.ID);
        }

        [TestMethod]
        public void LastName_SetAndGet_ReturnsCorrectValue()
        {
            var person = new ConcretePerson { LastName = "TestName" };
            Assert.AreEqual("TestName", person.LastName);
        }

        [TestMethod]
        public void FirstMidName_SetAndGet_ReturnsCorrectValue()
        {
            var person = new ConcretePerson { FirstMidName = "TestFirst" };
            Assert.AreEqual("TestFirst", person.FirstMidName);
        }
    }

    [TestClass]
