using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Services;
using ContosoUniversity.Models;
using System;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class NotificationServiceTests
    {
        private NotificationService _service;

        [TestInitialize]
        public void Setup()
        {
            _service = new NotificationService();
            // Drain the static queue to avoid test interference
            while (_service.ReceiveNotification() != null) { }
        }

        [TestCleanup]
        public void Cleanup()
        {
            _service?.Dispose();
        }

        [TestMethod]
        public void SendNotification_WithDisplayName_EnqueuesNotification()
        {
            // Act
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "admin");

            // Assert
            var received = _service.ReceiveNotification();
            Assert.IsNotNull(received);
            Assert.AreEqual("Student", received.EntityType);
            Assert.AreEqual("1", received.EntityId);
            Assert.AreEqual("CREATE", received.Operation);
            Assert.AreEqual("admin", received.CreatedBy);
            Assert.IsFalse(received.IsRead);
        }

        [TestMethod]
        public void SendNotification_WithoutDisplayName_EnqueuesNotification()
        {
            // Act
            _service.SendNotification("Course", "100", EntityOperation.UPDATE, "teacher");

            // Assert
            var received = _service.ReceiveNotification();
            Assert.IsNotNull(received);
            Assert.AreEqual("Course", received.EntityType);
            Assert.AreEqual("100", received.EntityId);
            Assert.AreEqual("UPDATE", received.Operation);
            Assert.AreEqual("teacher", received.CreatedBy);
        }

        [TestMethod]
        public void SendNotification_DefaultUserName_IsSystem()
        {
            // Act
            _service.SendNotification("Department", "5", EntityOperation.DELETE);

            // Assert
            var received = _service.ReceiveNotification();
            Assert.IsNotNull(received);
            Assert.AreEqual("System", received.CreatedBy);
        }

        [TestMethod]
        public void SendNotification_SetsCreatedAt()
        {
            // Arrange
            var before = DateTime.Now;

            // Act
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            // Assert
            var after = DateTime.Now;
            var received = _service.ReceiveNotification();
            Assert.IsNotNull(received);
            Assert.IsTrue(received.CreatedAt >= before && received.CreatedAt <= after);
        }

        [TestMethod]
        public void ReceiveNotification_WhenEmpty_ReturnsNull()
        {
            var result = _service.ReceiveNotification();
            Assert.IsNull(result);
        }

        [TestMethod]
        public void ReceiveNotification_ReturnsFIFOOrder()
        {
            // Arrange
            _service.SendNotification("First", "1", EntityOperation.CREATE);
            _service.SendNotification("Second", "2", EntityOperation.UPDATE);

            // Act & Assert
            var first = _service.ReceiveNotification();
            Assert.AreEqual("First", first.EntityType);

            var second = _service.ReceiveNotification();
            Assert.AreEqual("Second", second.EntityType);

            var third = _service.ReceiveNotification();
            Assert.IsNull(third);
        }

        [TestMethod]
        public void SendNotification_CreateOperation_GeneratesCorrectMessage_WithDisplayName()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);
            var received = _service.ReceiveNotification();
            Assert.AreEqual("New Student 'John Doe' has been created", received.Message);
        }

        [TestMethod]
        public void SendNotification_UpdateOperation_GeneratesCorrectMessage_WithDisplayName()
        {
            _service.SendNotification("Course", "100", "Chemistry", EntityOperation.UPDATE);
            var received = _service.ReceiveNotification();
            Assert.AreEqual("Course 'Chemistry' has been updated", received.Message);
        }

        [TestMethod]
        public void SendNotification_DeleteOperation_GeneratesCorrectMessage_WithDisplayName()
        {
            _service.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE);
            var received = _service.ReceiveNotification();
            Assert.AreEqual("Department 'Engineering' has been deleted", received.Message);
        }

        [TestMethod]
        public void SendNotification_CreateOperation_GeneratesCorrectMessage_WithoutDisplayName()
        {
            _service.SendNotification("Student", "42", EntityOperation.CREATE);
            var received = _service.ReceiveNotification();
            Assert.AreEqual("New Student (ID: 42) has been created", received.Message);
        }

        [TestMethod]
        public void SendNotification_UpdateOperation_GeneratesCorrectMessage_WithoutDisplayName()
        {
            _service.SendNotification("Course", "100", EntityOperation.UPDATE);
            var received = _service.ReceiveNotification();
            Assert.AreEqual("Course (ID: 100) has been updated", received.Message);
        }

        [TestMethod]
        public void SendNotification_DeleteOperation_GeneratesCorrectMessage_WithoutDisplayName()
        {
            _service.SendNotification("Department", "5", EntityOperation.DELETE);
            var received = _service.ReceiveNotification();
            Assert.AreEqual("Department (ID: 5) has been deleted", received.Message);
        }

        [TestMethod]
        public void SendNotification_NullDisplayName_UsesIdInMessage()
        {
            _service.SendNotification("Student", "99", null, EntityOperation.CREATE);
            var received = _service.ReceiveNotification();
            Assert.AreEqual("New Student (ID: 99) has been created", received.Message);
        }

        [TestMethod]
        public void SendNotification_EmptyDisplayName_UsesIdInMessage()
        {
            _service.SendNotification("Student", "99", "", EntityOperation.CREATE);
            var received = _service.ReceiveNotification();
            Assert.AreEqual("New Student (ID: 99) has been created", received.Message);
        }

        [TestMethod]
        public void SendNotification_WhitespaceDisplayName_UsesIdInMessage()
        {
            _service.SendNotification("Student", "99", "   ", EntityOperation.CREATE);
            var received = _service.ReceiveNotification();
            Assert.AreEqual("New Student (ID: 99) has been created", received.Message);
        }

        [TestMethod]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op for in-memory implementation - just verify no exception
            _service.MarkAsRead(1);
            _service.MarkAsRead(999);
            _service.MarkAsRead(-1);
        }

        [TestMethod]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            service.Dispose();
            // Double dispose should also not throw
            service.Dispose();
        }

        [TestMethod]
        public void SendNotification_IsReadDefaultFalse()
        {
            _service.SendNotification("Test", "1", EntityOperation.CREATE);
            var received = _service.ReceiveNotification();
            Assert.IsFalse(received.IsRead);
        }

        [TestMethod]
        public void SendNotification_NullUserName_DefaultsToSystem()
        {
            _service.SendNotification("Test", "1", "Name", EntityOperation.CREATE, null);
            var received = _service.ReceiveNotification();
            Assert.AreEqual("System", received.CreatedBy);
        }
    }
}

