+using Microsoft.VisualStudio.TestTools.UnitTesting;
+using ContosoUniversity;
+using System;
+using System.Collections.Generic;
+using System.Linq;
+
+namespace ContosoUniversity.Tests
+{
+    [TestClass]
+    public sealed class PaginatedListTests
+    {
+        [TestMethod]
+        public void Constructor_SetsPageIndex()
+        {
+            // Arrange & Act
+            var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, 10, 2, 5);
+
+            // Assert
+            Assert.AreEqual(2, list.PageIndex);
+        }
+
+        [TestMethod]
+        public void Constructor_CalculatesTotalPages_ExactDivision()
+        {
+            // 10 items, 5 per page = 2 pages
+            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
+            Assert.AreEqual(2, list.TotalPages);
+        }
+
+        [TestMethod]
+        public void Constructor_CalculatesTotalPages_WithRemainder()
+        {
+            // 11 items, 5 per page = 3 pages (rounds up)
+            var list = new PaginatedList<int>(new List<int>(), 11, 1, 5);
+            Assert.AreEqual(3, list.TotalPages);
+        }
+
+        [TestMethod]
+        public void Constructor_CalculatesTotalPages_SingleItem()
+        {
+            var list = new PaginatedList<int>(new List<int>(), 1, 1, 10);
+            Assert.AreEqual(1, list.TotalPages);
+        }
+
+        [TestMethod]
+        public void Constructor_CalculatesTotalPages_ZeroItems()
+        {
+            var list = new PaginatedList<int>(new List<int>(), 0, 1, 10);
+            Assert.AreEqual(0, list.TotalPages);
+        }
+
+        [TestMethod]
+        public void Constructor_AddsItemsToList()
+        {
+            var items = new List<string> { "a", "b", "c" };
+            var list = new PaginatedList<string>(items, 3, 1, 10);
+
+            Assert.AreEqual(3, list.Count);
+            Assert.AreEqual("a", list[0]);
+            Assert.AreEqual("b", list[1]);
+            Assert.AreEqual("c", list[2]);
+        }
+
+        [TestMethod]
+        public void HasPreviousPage_FirstPage_ReturnsFalse()
+        {
+            var list = new PaginatedList<int>(new List<int>(), 20, 1, 10);
+            Assert.IsFalse(list.HasPreviousPage);
+        }
+
+        [TestMethod]
+        public void HasPreviousPage_SecondPage_ReturnsTrue()
+        {
+            var list = new PaginatedList<int>(new List<int>(), 20, 2, 10);
+            Assert.IsTrue(list.HasPreviousPage);
+        }
+
+        [TestMethod]
+        public void HasPreviousPage_ThirdPage_ReturnsTrue()
+        {
+            var list = new PaginatedList<int>(new List<int>(), 30, 3, 10);
+            Assert.IsTrue(list.HasPreviousPage);
+        }
+
+        [TestMethod]
+        public void HasNextPage_OnLastPage_ReturnsFalse()
+        {
+            // 20 items, 10 per page = 2 pages, on page 2
+            var list = new PaginatedList<int>(new List<int>(), 20, 2, 10);
+            Assert.IsFalse(list.HasNextPage);
+        }
+
+        [TestMethod]
+        public void HasNextPage_BeforeLastPage_ReturnsTrue()
+        {
+            // 20 items, 10 per page = 2 pages, on page 1
+            var list = new PaginatedList<int>(new List<int>(), 20, 1, 10);
+            Assert.IsTrue(list.HasNextPage);
+        }
+
+        [TestMethod]
+        public void HasNextPage_ZeroTotalPages_ReturnsFalse()
+        {
+            var list = new PaginatedList<int>(new List<int>(), 0, 1, 10);
+            Assert.IsFalse(list.HasNextPage);
+        }
+
+        [TestMethod]
+        public void Create_PaginatesCorrectly_FirstPage()
+        {
+            // Arrange
+            var source = Enumerable.Range(1, 25).AsQueryable();
+
+            // Act
+            var result = PaginatedList<int>.Create(source, 1, 10);
+
+            // Assert
+            Assert.AreEqual(10, result.Count);
+            Assert.AreEqual(1, result.PageIndex);
+            Assert.AreEqual(3, result.TotalPages);
+            Assert.AreEqual(1, result[0]);
+            Assert.AreEqual(10, result[9]);
+        }
+
+        [TestMethod]
+        public void Create_PaginatesCorrectly_SecondPage()
+        {
+            var source = Enumerable.Range(1, 25).AsQueryable();
+
+            var result = PaginatedList<int>.Create(source, 2, 10);
+
+            Assert.AreEqual(10, result.Count);
+            Assert.AreEqual(2, result.PageIndex);
+            Assert.AreEqual(11, result[0]);
+            Assert.AreEqual(20, result[9]);
+        }
+
+        [TestMethod]
+        public void Create_PaginatesCorrectly_LastPage()
+        {
+            var source = Enumerable.Range(1, 25).AsQueryable();
+
+            var result = PaginatedList<int>.Create(source, 3, 10);
+
+            Assert.AreEqual(5, result.Count);
+            Assert.AreEqual(3, result.PageIndex);
+            Assert.AreEqual(21, result[0]);
+            Assert.AreEqual(25, result[4]);
+        }
+
+        [TestMethod]
+        public void Create_EmptySource_ReturnsEmptyList()
+        {
+            var source = Enumerable.Empty<int>().AsQueryable();
+
+            var result = PaginatedList<int>.Create(source, 1, 10);
+
+            Assert.AreEqual(0, result.Count);
+            Assert.AreEqual(0, result.TotalPages);
+            Assert.AreEqual(1, result.PageIndex);
+        }
+
+        [TestMethod]
+        public void Create_SinglePage_NoExtraPages()
+        {
+            var source = Enumerable.Range(1, 5).AsQueryable();
+
+            var result = PaginatedList<int>.Create(source, 1, 10);
+
+            Assert.AreEqual(5, result.Count);
+            Assert.AreEqual(1, result.TotalPages);
+            Assert.IsFalse(result.HasPreviousPage);
+            Assert.IsFalse(result.HasNextPage);
+        }
+
+        [TestMethod]
+        public void Create_ExactlyOnePageSize_OnePage()
+        {
+            var source = Enumerable.Range(1, 10).AsQueryable();
+
+            var result = PaginatedList<int>.Create(source, 1, 10);
+
+            Assert.AreEqual(10, result.Count);
+            Assert.AreEqual(1, result.TotalPages);
+        }
+
+        [TestMethod]
+        [DataRow(1, 10, 1, DisplayName = "10 items, page 1 of 1")]
+        [DataRow(15, 10, 2, DisplayName = "15 items, 2 pages")]
+        [DataRow(100, 10, 10, DisplayName = "100 items, 10 pages")]
+        [DataRow(1, 1, 1, DisplayName = "1 item, 1 per page")]
+        [DataRow(3, 1, 3, DisplayName = "3 items, 1 per page, 3 pages")]
+        public void Constructor_CalculatesTotalPages_VariousInputs(int count, int pageSize, int expectedTotalPages)
+        {
+            var list = new PaginatedList<int>(new List<int>(), count, 1, pageSize);
+            Assert.AreEqual(expectedTotalPages, list.TotalPages);
+        }
+
+        [TestMethod]
+        public void Create_WithStringType_WorksCorrectly()
+        {
+            var source = new[] { "apple", "banana", "cherry", "date", "elderberry" }.AsQueryable();
+
+            var result = PaginatedList<string>.Create(source, 1, 3);
+
+            Assert.AreEqual(3, result.Count);
+            Assert.AreEqual("apple", result[0]);
+            Assert.AreEqual("cherry", result[2]);
+            Assert.AreEqual(2, result.TotalPages);
+        }
+    }
+}
