using Microsoft.Extensions.Logging;
using Moq;
using System;
using System.IO;
using System.Linq;
using System.Net;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class CoursesControllerTests
    {
        private SchoolContext _context;
        private CoursesController _controller;
        private Mock<IWebHostEnvironment> _mockEnv;
        private Mock<ILogger<CoursesController>> _mockLogger;

        [TestInitialize]
        public void Setup()
        {
            _context = TestHelper.CreateInMemoryContext();
            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockLogger = new Mock<ILogger<CoursesController>>();

            // Set up a temporary WebRootPath for file upload tests
            var tempPath = Path.Combine(Path.GetTempPath(), "CoursesControllerTests_" + Guid.NewGuid().ToString("N"));
            Directory.CreateDirectory(tempPath);
            _mockEnv.Setup(e => e.WebRootPath).Returns(tempPath);
            _mockEnv.Setup(e => e.ContentRootPath).Returns(tempPath);

            _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
            TestHelper.SetupControllerContext(_controller);

            // Seed departments and courses
            _context.Departments.Add(new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 350000,
                StartDate = DateTime.Parse("2007-09-01")
            });
            _context.Courses.AddRange(
                new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 },
                new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 1 }
            );
            _context.SaveChanges();
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();

            // Clean up temp directory
            var path = _mockEnv.Object.WebRootPath;
            if (Directory.Exists(path))
            {
                try { Directory.Delete(path, true); } catch { }
            }
        }

        // ---------- Index ----------

        [TestMethod]
        public void Index_ReturnsViewWithCourses()
        {
            var result = _controller.Index();

            Assert.IsInstanceOfType(result, typeof(ViewResult));
            var viewResult = (ViewResult)result;
            var model = viewResult.Model as System.Collections.Generic.List<Course>;
            Assert.IsNotNull(model);
            Assert.AreEqual(2, model.Count);
        }

        // ---------- Details ----------

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            Assert.IsInstanceOfType(result, typeof(StatusCodeResult));
            Assert.AreEqual((int)HttpStatusCode.BadRequest, ((StatusCodeResult)result).StatusCode);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Details(1050);

            Assert.IsInstanceOfType(result, typeof(ViewResult));
            var course = ((ViewResult)result).Model as Course;
            Assert.IsNotNull(course);
            Assert.AreEqual("Chemistry", course.Title);
        }

        // ---------- Create (GET) ----------

        [TestMethod]
        public void Create_Get_ReturnsViewWithNewCourse()
        {
            var result = _controller.Create();

            Assert.IsInstanceOfType(result, typeof(ViewResult));
            var viewResult = (ViewResult)result;
            var model = viewResult.Model as Course;
            Assert.IsNotNull(model);
        }

        // ---------- Create (POST) ----------

        [TestMethod]
        public void Create_Post_ValidModel_NoImage_RedirectsToIndex()
        {
            var course = new Course
            {
                CourseID = 9999,
                Title = "New Course",
                Credits = 3,
                DepartmentID = 1
            };

            var result = _controller.Create(course, null);

            Assert.IsInstanceOfType(result, typeof(RedirectToActionResult));
            Assert.AreEqual("Index", ((RedirectToActionResult)result).ActionName);
        }

