        [TestMethod]
        public void Create_Post_InvalidImageExtension_ReturnsViewWithError()
        {
            var course = new Course
            {
                CourseID = 7777,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = 1
            };

            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns("test.exe");
            mockFile.Setup(f => f.Length).Returns(1024);

            var result = _controller.Create(course, mockFile.Object);

            Assert.IsInstanceOfType(result, typeof(ViewResult));
            Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [TestMethod]
        public void Create_Post_ImageTooLarge_ReturnsViewWithError()
        {
            var course = new Course
            {
                CourseID = 6666,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = 1
            };

            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns("test.jpg");
            mockFile.Setup(f => f.Length).Returns(10 * 1024 * 1024); // 10MB

            var result = _controller.Create(course, mockFile.Object);

            Assert.IsInstanceOfType(result, typeof(ViewResult));
            Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [TestMethod]
        public void Create_Post_ValidImage_SavesCourseAndSetsImagePath()
        {
            var course = new Course
            {
                CourseID = 5555,
                Title = "Image Course",
                Credits = 3,
                DepartmentID = 1
            };

            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns("test.jpg");
            mockFile.Setup(f => f.Length).Returns(1024);
            mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>()));

            var result = _controller.Create(course, mockFile.Object);

            Assert.IsInstanceOfType(result, typeof(RedirectToActionResult));
            var savedCourse = _context.Courses.Find(5555);
            Assert.IsNotNull(savedCourse);
            Assert.IsTrue(savedCourse.TeachingMaterialImagePath.StartsWith("/Uploads/TeachingMaterials/"));
        }

        [TestMethod]
        [DataRow(".jpg", DisplayName = "JPEG extension")]
        [DataRow(".jpeg", DisplayName = "JPEG long extension")]
        [DataRow(".png", DisplayName = "PNG extension")]
        [DataRow(".gif", DisplayName = "GIF extension")]
        [DataRow(".bmp", DisplayName = "BMP extension")]
        public void Create_Post_AllowedImageExtensions_AreAccepted(string extension)
        {
            var course = new Course
            {
                CourseID = 1111 + Math.Abs(extension.GetHashCode() % 1000),
                Title = "Test " + extension,
                Credits = 3,
                DepartmentID = 1
            };

            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns("test" + extension);
            mockFile.Setup(f => f.Length).Returns(1024);
            mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>()));

            var result = _controller.Create(course, mockFile.Object);

            Assert.IsInstanceOfType(result, typeof(RedirectToActionResult));
        }

