        }

        // ---------- Delete (GET) ----------

        [TestMethod]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            Assert.IsInstanceOfType(result, typeof(StatusCodeResult));
            Assert.AreEqual((int)HttpStatusCode.BadRequest, ((StatusCodeResult)result).StatusCode);
        }

        [TestMethod]
        public void Delete_Get_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Delete(1050);

            Assert.IsInstanceOfType(result, typeof(ViewResult));
            var course = ((ViewResult)result).Model as Course;
            Assert.IsNotNull(course);
            Assert.AreEqual("Chemistry", course.Title);
        }

        // ---------- DeleteConfirmed ----------

        [TestMethod]
        public void DeleteConfirmed_ValidId_RedirectsToIndex()
        {
            var result = _controller.DeleteConfirmed(1050);

            Assert.IsInstanceOfType(result, typeof(RedirectToActionResult));
            Assert.AreEqual("Index", ((RedirectToActionResult)result).ActionName);
        }

        [TestMethod]
        public void DeleteConfirmed_ValidId_RemovesCourseFromDatabase()
        {
            _controller.DeleteConfirmed(1050);

            Assert.AreEqual(1, _context.Courses.Count());
            Assert.IsNull(_context.Courses.Find(1050));
        }

        [TestMethod]
        public void DeleteConfirmed_CourseWithImage_DeletesImageFile()
        {
            // Set up a course with an image path
            var course = _context.Courses.Find(1050);
            var uploadsDir = Path.Combine(_mockEnv.Object.WebRootPath, "Uploads", "TeachingMaterials");
            Directory.CreateDirectory(uploadsDir);
            var filePath = Path.Combine(uploadsDir, "test_image.jpg");
            File.WriteAllText(filePath, "test");
            course.TeachingMaterialImagePath = "/Uploads/TeachingMaterials/test_image.jpg";
            _context.SaveChanges();

            _controller.DeleteConfirmed(1050);

            Assert.IsFalse(File.Exists(filePath));
        }
    }
