using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class InstructorsControllerTests
    {
        private SchoolContext _context;
        private InstructorsController _controller;

        [TestInitialize]
        public void Setup()
        {
            _context = TestHelper.CreateInMemoryContext();
            _controller = new InstructorsController(_context);
            TestHelper.SetupControllerContext(_controller);

            // Seed data
            var instructor1 = new Instructor
            {
                ID = 1,
                FirstMidName = "Kim",
                LastName = "Abercrombie",
                HireDate = DateTime.Parse("1995-03-11"),
                CourseAssignments = new List<CourseAssignment>(),
                OfficeAssignment = new OfficeAssignment { InstructorID = 1, Location = "Room 101" }
            };
            var instructor2 = new Instructor
            {
                ID = 2,
                FirstMidName = "Fadi",
                LastName = "Fakhouri",
                HireDate = DateTime.Parse("2002-07-06"),
                CourseAssignments = new List<CourseAssignment>()
            };
            _context.Instructors.AddRange(instructor1, instructor2);

            _context.Departments.Add(new Department
            {
                DepartmentID = 1,
                Name = "English",
                Budget = 350000,
                StartDate = DateTime.Parse("2007-09-01"),
                InstructorID = 1
            });

            var course1 = new Course
            {
                CourseID = 2021,
                Title = "Composition",
                Credits = 3,
                DepartmentID = 1,
                Enrollments = new List<Enrollment>()
            };
            var course2 = new Course
            {
                CourseID = 2042,
                Title = "Literature",
                Credits = 4,
                DepartmentID = 1,
                Enrollments = new List<Enrollment>()
            };
            _context.Courses.AddRange(course1, course2);

            _context.CourseAssignments.Add(new CourseAssignment
            {
                InstructorID = 1,
                CourseID = 2021
            });

            _context.SaveChanges();
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        // ---------- Index ----------

        [TestMethod]
        public void Index_NoParams_ReturnsViewWithInstructors()
        {
            var result = _controller.Index(null, null);

            Assert.IsInstanceOfType(result, typeof(ViewResult));
            var viewResult = (ViewResult)result;
            var model = viewResult.Model as InstructorIndexData;
            Assert.IsNotNull(model);
            Assert.IsNotNull(model.Instructors);
            Assert.AreEqual(2, model.Instructors.Count());
        }

        [TestMethod]
        public void Index_OrdersInstructorsByLastName()
        {
            var result = (ViewResult)_controller.Index(null, null);
            var model = (InstructorIndexData)result.Model;

            Assert.AreEqual("Abercrombie", model.Instructors.First().LastName);
            Assert.AreEqual("Fakhouri", model.Instructors.Last().LastName);
        }

        [TestMethod]
        public void Index_WithInstructorId_PopulatesCourses()
        {
            var result = (ViewResult)_controller.Index(1, null);
            var model = (InstructorIndexData)result.Model;

            Assert.IsNotNull(model.Courses);
            Assert.AreEqual(1, model.Courses.Count());
            Assert.AreEqual("Composition", model.Courses.First().Title);
        }

