            _controller.Index(1, null);

            Assert.AreEqual(1, _controller.ViewBag.InstructorID);
        }

        [TestMethod]
        public void Index_WithCourseId_PopulatesEnrollments()
        {
            // Add an enrollment for the course
            _context.Students.Add(new Student
            {
                ID = 10,
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.Parse("2024-01-01")
            });
