        // ---------- Create (POST) ----------

        [TestMethod]
        public void Create_Post_ValidModel_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2024-01-01")
            };

