using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using System;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class NotificationsControllerTests
    {
        private SchoolContext _context;
        private NotificationsController _controller;

        [TestInitialize]
        public void Setup()
        {
            _context = TestHelper.CreateInMemoryContext();
            _controller = new NotificationsController(_context);
            TestHelper.SetupControllerContext(_controller);

            // Drain the static notification queue
            var drainService = new NotificationService();
            while (drainService.ReceiveNotification() != null) { }
            drainService.Dispose();
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        // ---------- Index ----------

        [TestMethod]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index();

            Assert.IsInstanceOfType(result, typeof(ViewResult));
        }

        // ---------- GetNotifications ----------

        [TestMethod]
        public void GetNotifications_WhenEmpty_ReturnsSuccessWithEmptyList()
        {
            var result = _controller.GetNotifications();

            Assert.IsInstanceOfType(result, typeof(JsonResult));
            var json = result.Value;
            Assert.IsNotNull(json);

            // Use reflection to check dynamic properties
            var successProp = json.GetType().GetProperty("success");
            Assert.IsNotNull(successProp);
            Assert.AreEqual(true, successProp.GetValue(json));

            var countProp = json.GetType().GetProperty("count");
            Assert.IsNotNull(countProp);
            Assert.AreEqual(0, countProp.GetValue(json));
        }

        [TestMethod]
        public void GetNotifications_WithQueuedNotifications_ReturnsNotifications()
        {
            // Enqueue a notification
            var service = new NotificationService();
            service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "admin");

            var result = _controller.GetNotifications();

            var json = result.Value;
            var successProp = json.GetType().GetProperty("success");
            Assert.AreEqual(true, successProp.GetValue(json));

            var countProp = json.GetType().GetProperty("count");
            var count = (int)countProp.GetValue(json);
            Assert.IsTrue(count >= 1);

            service.Dispose();
        }

        [TestMethod]
        public void GetNotifications_LimitsToTenNotifications()
        {
            // Enqueue 15 notifications
            var service = new NotificationService();
            for (int i = 0; i < 15; i++)
            {
                service.SendNotification("Student", i.ToString(), EntityOperation.CREATE);
            }

            var result = _controller.GetNotifications();

            var json = result.Value;
            var countProp = json.GetType().GetProperty("count");
            var count = (int)countProp.GetValue(json);
            Assert.IsTrue(count <= 10);

            service.Dispose();
        }

        // ---------- MarkAsRead ----------

        [TestMethod]
        public void MarkAsRead_ReturnsSuccessJson()
        {
            var result = _controller.MarkAsRead(1);

            Assert.IsInstanceOfType(result, typeof(JsonResult));
            var json = result.Value;
            var successProp = json.GetType().GetProperty("success");
            Assert.AreEqual(true, successProp.GetValue(json));
        }

        [TestMethod]
        public void MarkAsRead_InvalidId_StillReturnsSuccess()
        {
            // MarkAsRead is a no-op for in-memory implementation
            var result = _controller.MarkAsRead(999);

            var json = result.Value;
            var successProp = json.GetType().GetProperty("success");
            Assert.AreEqual(true, successProp.GetValue(json));
        }
    }
}

